const raw = $input.first().json.body || $input.first().json || {};
const session_id = raw.session_id || '';
const request_id = raw.request_id || '';
const msg = String(raw.message || '').trim() || 'Hello';
const turn = Number(raw.turn_index || 1);
const lang = String((raw.context && raw.context.language) || 'en');
const canton = String((raw.context && raw.context.canton) || 'ZH').slice(0, 2);
const startMs = Date.now();

let reply = '', genStatus = 'heuristic', genError = null, usedModel = '';

try {
  let apiKey = '';
  try { apiKey = process.env.NVIDIA_API_KEY || ''; } catch(_) {}
  if (!apiKey) try { apiKey = (typeof $env !== 'undefined' && $env.NVIDIA_API_KEY) || ''; } catch(_) {}
  let apiUrl = '';
  try { apiUrl = process.env.NVIDIA_API_URL || ''; } catch(_) {}
  if (!apiUrl) try { apiUrl = (typeof $env !== 'undefined' && $env.NVIDIA_API_URL) || ''; } catch(_) {}
  if (!apiUrl) apiUrl = 'https://integrate.api.nvidia.com/v1/chat/completions';
  let model = '';
  try { model = process.env.NVIDIA_MODEL || ''; } catch(_) {}
  if (!model) try { model = (typeof $env !== 'undefined' && $env.NVIDIA_MODEL) || ''; } catch(_) {}
  if (!model) model = 'google/gemma-3n-e4b-it';
  usedModel = model;

  if (apiKey && apiKey.length > 10) {
    const sysPrompt = 'You are Big5Loop, a warm and supportive assistant for informal caregivers in Switzerland. Reply in 2-3 sentences. Be empathetic, genuine, and ask one follow-up question. Language: ' + lang + '.';
    const body = await this.helpers.httpRequest({
      url: apiUrl,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey },
      body: { model: model, messages: [{role:'user', content: sysPrompt + '\n\nUser: ' + msg}], temperature: 0.6, max_tokens: 150 },
      timeout: 15000,
      json: true
    });
    const c = body && body.choices && body.choices[0] && body.choices[0].message && body.choices[0].message.content;
    if (c && c.length > 10) { reply = c; genStatus = 'nvidia'; }
    else { genError = 'API returned empty content'; }
  } else { genError = 'No API key'; }
} catch(e) { genError = e.message || String(e); }

if (!reply) reply = "I'm here to listen and support you. How are you feeling today?";

const durationMs = Math.max(0, Date.now() - startMs);
const nowIso = new Date().toISOString();

return [{ json: {
  session_id: session_id,
  message: { role: 'assistant', content: reply, timestamp: nowIso },
  personality_state: { ocean: {O:0,C:0,E:0,A:0,N:0}, stable: false, confidence: {}, ema_applied: false },
  policy_navigation: { active: false, citations: [], grounding: { status: 'skipped' } },
  regulation: { directives: ['Be warm, attentive, and supportive'], zurich_applied: false },
  pipeline_status: { detector: 'skipped', generator: genStatus, verifier: 'skipped', retrieval: 'skipped', grounding: 'skipped', fact_invariance_check: 'skipped' },
  debug: { generation_error: genError, turn_index: turn, model_tier_requested: 'light', model_tier_effective: 'light', model: usedModel },
  coaching_mode: 'emotional_support',
  mode_confidence: null,
  request_id: request_id,
  reply: reply,
  stage_timings: [
    { stage: 'detection', status: 'skipped', duration_ms: 0 },
    { stage: 'routing', status: 'simple', duration_ms: 0 },
    { stage: 'retrieval', status: 'skipped', duration_ms: 0 },
    { stage: 'generation', status: genStatus === 'nvidia' ? 'ok' : 'fallback', duration_ms: durationMs },
    { stage: 'grounding', status: 'skipped', duration_ms: 0 },
    { stage: 'verification', status: 'skipped', duration_ms: 0 },
    { stage: 'end_to_end', status: 'ok', duration_ms: durationMs }
  ]
}}];
